struct TodayEventsRectangularWidget_: Widget { let kind = "TodayEventsRectangular"; var body: some WidgetConfiguration { StaticConfiguration(kind: kind, provider: IslandLinkProvider()) { entry in TodayEventsRectangularWidget(entry: entry).containerBackground(.fill.tertiary, for: .widget) }.configurationDisplayName("今日/明日").description("对比今天事项和明天开庭数").supportedFamilies([.accessoryRectangular]) } }
struct QuickActionsSmallWidget_: Widget { let kind = "QuickActionsSmall"; var body: some WidgetConfiguration { StaticConfiguration(kind: kind, provider: IslandLinkProvider()) { entry in QuickActionsSmallWidget(entry: entry).containerBackground(.fill.tertiary, for: .widget) }.configurationDisplayName("快捷操作").description("快速新建事件、联系人、案件").supportedFamilies([.systemSmall]) } }
struct CaseOverviewMediumWidget_: Widget { let kind = "CaseOverviewMedium"; var body: some WidgetConfiguration { StaticConfiguration(kind: kind, provider: IslandLinkProvider()) { entry in CaseOverviewMediumWidget(entry: entry).containerBackground(.fill.tertiary, for: .widget) }.configurationDisplayName("案件概览").description("进行中案件数及状态分布").supportedFamilies([.systemMedium]) } }
@main struct IslandLinkWidgetBundle: WidgetBundle { var body: some Widget { TodayEventsCircularWidget(); TodayEventsInlineWidget_(); TodayEventsRectangularWidget_(); QuickActionsSmallWidget_(); CaseOverviewMediumWidget_() } }